spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var p1 = 0.20; // 24 -> 2, 12
    var p2 = 0.40; // 12 -> 2, 6
    var p3 = 0.60; // 6 -> 2, 3
    var p4 = 0.90; // highlight primes + show formula

    // Node coordinates
    var n24 = { x: W / 2, y: H * 0.18, label: '24', isPrime: false };

    var n2_L1 = { x: W / 2 - 65, y: H * 0.38, label: '2', isPrime: true };
    var n12_L1 = { x: W / 2 + 65, y: H * 0.38, label: '12', isPrime: false };

    var n2_L2 = { x: W / 2 + 10, y: H * 0.58, label: '2', isPrime: true };
    var n6_L2 = { x: W / 2 + 120, y: H * 0.58, label: '6', isPrime: false };

    var n2_L3 = { x: W / 2 + 75, y: H * 0.78, label: '2', isPrime: true };
    var n3_L3 = { x: W / 2 + 165, y: H * 0.78, label: '3', isPrime: true };

    function drawNode(node, active) {
      if (!active) return;

      var radius = 16;
      ctx.beginPath();
      ctx.arc(node.x, node.y, radius, 0, Math.PI * 2);

      if (node.isPrime && progress >= p4) {
        // Circle primes in green
        ctx.fillStyle = '#10B981';
        ctx.fill();
        ctx.strokeStyle = '#34D399';
        ctx.lineWidth = 2.5;
        ctx.stroke();
      } else {
        ctx.fillStyle = '#374151';
        ctx.fill();
        ctx.strokeStyle = '#4B5563';
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }

      ctx.fillStyle = '#FFFFFF';
      ctx.font = 'bold 12px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(node.label, node.x, node.y);
    }

    function drawBranch(parent, child, active) {
      if (!active) return;
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(parent.x, parent.y + 16);
      ctx.lineTo(child.x, child.y - 16);
      ctx.stroke();
    }

    // Root is always drawn
    drawNode(n24, true);

    // Level 1 branches
    drawBranch(n24, n2_L1, progress >= p1);
    drawBranch(n24, n12_L1, progress >= p1);
    drawNode(n2_L1, progress >= p1);
    drawNode(n12_L1, progress >= p1);

    // Level 2 branches
    drawBranch(n12_L1, n2_L2, progress >= p2);
    drawBranch(n12_L1, n6_L2, progress >= p2);
    drawNode(n2_L2, progress >= p2);
    drawNode(n6_L2, progress >= p2);

    // Level 3 branches
    drawBranch(n6_L2, n2_L3, progress >= p3);
    drawBranch(n6_L2, n3_L3, progress >= p3);
    drawNode(n2_L3, progress >= p3);
    drawNode(n3_L3, progress >= p3);

    // Display formula at the end
    if (progress >= p4) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.textAlign = 'left';
      ctx.fillText('24 = 2 * 2 * 2 * 3 = 2³ * 3', 30, H - 40);

      ctx.fillStyle = '#34D399';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Prime leaves highlighted!', 30, H - 20);
    } else {
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '14px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('Factoring 24 step-by-step', W / 2, H - 30);
    }
  }
};
